def chart_layout(title="", h=300):
    return dict(
        title=dict(text=title, font=dict(color=C_MUTED, size=12), x=0),
        paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor=C_BG,
        font=dict(color=C_TEXT, size=11),
        legend=dict(bgcolor="rgba(0,0,0,0)", font=dict(color=C_MUTED)),
        margin=dict(l=10, r=10, t=40, b=10),
        xaxis=dict(gridcolor=C_BORDER, zerolinecolor=C_BORDER, color=C_MUTED),
        yaxis=dict(gridcolor=C_BORDER, zerolinecolor=C_BORDER, color=C_MUTED),
        height=h,
    )

def encode_input(task, compl, deliv):
    try: te = le_task.transform([task])[0]
    except: te = 0
    try: ce = le_compl.transform([compl])[0]
    except: ce = 0
    try: de = le_deliv.transform([deliv])[0]
    except: de = 0
    return te, ce, de

